// main.bicep — provision App Service + SQL Database in one deployment
param location string = resourceGroup().location
param appName string = 'myapp'

// App Service Plan (PremiumV3 tier)
resource plan 'Microsoft.Web/serverfarms@2023-01-01' = {
  name: '${appName}-plan'
  location: location
  sku: { name: 'P1v3', tier: 'PremiumV3', capacity: 1 }
}

// Web App
resource app 'Microsoft.Web/sites@2023-01-01' = {
  name: appName
  location: location
  properties: { serverFarmId: plan.id }
}

// SQL Logical Server
resource sqlServer 'Microsoft.Sql/servers@2023-05-01-preview' = {
  name: '${appName}-sql'
  location: location
  properties: {
    administratorLogin: 'sqladmin'
    administratorLoginPassword: 'P@ssw0rd1234!'  // use Key Vault reference in production
  }
}

// SQL Database (S2 tier)
resource db 'Microsoft.Sql/servers/databases@2023-05-01-preview' = {
  parent: sqlServer
  name: '${appName}-db'
  location: location
  sku: { name: 'S2', tier: 'Standard' }
}
